// Numeric enum (auto-incrementing)
enum Color {
  Red,
  Green,
  Blue,
}

// Numeric enum (explicit values)
enum Status {
  Active = 1,
  Inactive = 0,
}

// String enum
enum Direction {
  Up = "UP",
  Down = "DOWN",
  Left = "LEFT",
  Right = "RIGHT",
}

// Export enum
export enum Visibility {
  Public,
  Private,
  Protected,
}
